-- BARMM: Maguindanao(+Cotabato City), Lanao del Sur, Basilan, Sulu, Tawi-Tawi
-- BIR RDO 107(Maguindanao+CotabatoCity),102(Lanao Sur),94(Basilan),95(Sulu),96(Tawi-Tawi). Tolerant of OCR-garbled markers.
START TRANSACTION;
DELETE FROM zonal_values WHERE province IN ('MAGUINDANAO','LANAO DEL SUR','BASILAN','SULU','TAWI-TAWI');
COMMIT;
